8124 const SCEV *ScalarEvolution::getConstantMaxTripCountFromArray(const Loop *L) {
8125   // We can't infer from Array in Irregular Loop.
8126   // FIXME: It's hard to infer loop bound from array operated in Nested Loop.
8127   if (!L->isLoopSimplifyForm() || !L->isInnermost())
8128     return getCouldNotCompute();
8129 
8130   // FIXME: To make the scene more typical, we only analysis loops that have
8131   // one exiting block and that block must be the latch. To make it easier to
8132   // capture loops that have memory access and memory access will be executed
8133   // in each iteration.
8134   const BasicBlock *LoopLatch = L->getLoopLatch();
8135   assert(LoopLatch && "See defination of simplify form loop.");
8136   if (L->getExitingBlock() != LoopLatch)
8137     return getCouldNotCompute();
8138 
8139   const DataLayout &DL = getDataLayout();
8140   SmallVector<const SCEV *> InferCountColl;
8141   for (auto *BB : L->getBlocks()) {
8142     // Go here, we can know that Loop is a single exiting and simplified form
8143     // loop. Make sure that infer from Memory Operation in those BBs must be
8144     // executed in loop. First step, we can make sure that max execution time
8145     // of MemAccessBB in loop represents latch max excution time.
8146     // If MemAccessBB does not dom Latch, skip.
8147     //            Entry
8148     //              │
8149     //        ┌─────▼─────┐
8150     //        │Loop Header◄─────┐
8151     //        └──┬──────┬─┘     │
8152     //           │      │       │
8153     //  ┌────────▼──┐ ┌─▼─────┐ │
8154     //  │MemAccessBB│ │OtherBB│ │
8155     //  └────────┬──┘ └─┬─────┘ │
8156     //           │      │       │
8157     //         ┌─▼──────▼─┐     │
8158     //         │Loop Latch├─────┘
8159     //         └────┬─────┘
8160     //              ▼
8161     //             Exit
8162     if (!DT.dominates(BB, LoopLatch))
8163       continue;
8164 
8165     for (Instruction &Inst : *BB) {
8166       // Find Memory Operation Instruction.
8167       auto *GEP = getLoadStorePointerOperand(&Inst);
8168       if (!GEP)
8169         continue;
8170 
8171       auto *ElemSize = dyn_cast<SCEVConstant>(getElementSize(&Inst));
8172       // Do not infer from scalar type, eg."ElemSize = sizeof()".
8173       if (!ElemSize)
8174         continue;
8175 
8176       // Use a existing polynomial recurrence on the trip count.
8177       auto *AddRec = dyn_cast<SCEVAddRecExpr>(getSCEV(GEP));
8178       if (!AddRec)
8179         continue;
8180       auto *ArrBase = dyn_cast<SCEVUnknown>(getPointerBase(AddRec));
8181       auto *Step = dyn_cast<SCEVConstant>(AddRec->getStepRecurrence(*this));
8182       if (!ArrBase || !Step)
