8231       if (!InferCount || InferCount->getAPInt().getActiveBits() > 32)
8232         continue;
8233 
8234       InferCountColl.push_back(InferCount);
8235     }
8236   }
8237 
8238   if (InferCountColl.size() == 0)
8239     return getCouldNotCompute();
8240 
8241   return getUMinFromMismatchedTypes(InferCountColl);
