5102   // backedge guarding condition, we can also compute a backedge
5103   // taken count for the loop.  The exceptions are assumptions and
5104   // guards present in the loop -- SCEV is not great at exploiting
5105   // these to compute max backedge taken counts, but can still use
5106   // these to prove lack of overflow.  Use this fact to avoid
5107   // doing extra work that may not pay off.
5108 
5109   if (isa<SCEVCouldNotCompute>(MaxBECount) && !HasGuards &&
5110       AC.assumptions().empty())
5111     return Result;
5112 
5113   // If the backedge is guarded by a comparison with the pre-inc  value the
5114   // addrec is safe. Also, if the entry is guarded by a comparison with the
5115   // start value and the backedge is guarded by a comparison with the post-inc
5116   // value, the addrec is safe.
5117   ICmpInst::Predicate Pred;
5118   const SCEV *OverflowLimit =
5119     getSignedOverflowLimitForStep(Step, &Pred, this);
5120   if (OverflowLimit &&
5121       (isLoopBackedgeGuardedByCond(L, Pred, AR, OverflowLimit) ||
5122        isKnownOnEveryIteration(Pred, AR, OverflowLimit))) {
5123     Result = setFlags(Result, SCEV::FlagNSW);
5124   }
5125   return Result;
5126 }
5127 SCEV::NoWrapFlags
5128 ScalarEvolution::proveNoUnsignedWrapViaInduction(const SCEVAddRecExpr *AR) {
5129   SCEV::NoWrapFlags Result = AR->getNoWrapFlags();
5130 
5131   if (AR->hasNoUnsignedWrap())
5132     return Result;
5133 
5134   if (!AR->isAffine())
5135     return Result;
5136 
5137   // This function can be expensive, only try to prove NUW once per AddRec.
5138   if (!UnsignedWrapViaInductionTried.insert(AR).second)
5139     return Result;
5140 
5141   const SCEV *Step = AR->getStepRecurrence(*this);
5142   unsigned BitWidth = getTypeSizeInBits(AR->getType());
5143   const Loop *L = AR->getLoop();
5144 
5145   // Check whether the backedge-taken count is SCEVCouldNotCompute.
5146   // Note that this serves two purposes: It filters out loops that are
5147   // simply not analyzable, and it covers the case where this code is
5148   // being called from within backedge-taken count analysis, such that
5149   // attempting to ask for the backedge-taken count would likely result
5150   // in infinite recursion. In the later case, the analysis code will
5151   // cope with a conservative value, and it will take care to purge
5152   // that value once it has finished.
5153   const SCEV *MaxBECount = getConstantMaxBackedgeTakenCount(L);
5154 
5155   // Normally, in the cases we can prove no-overflow via a
5156   // backedge guarding condition, we can also compute a backedge
5157   // taken count for the loop.  The exceptions are assumptions and
5158   // guards present in the loop -- SCEV is not great at exploiting
5159   // these to compute max backedge taken counts, but can still use
5160   // these to prove lack of overflow.  Use this fact to avoid
5161   // doing extra work that may not pay off.
5162 
5163   if (isa<SCEVCouldNotCompute>(MaxBECount) && !HasGuards &&
5164       AC.assumptions().empty())
5165     return Result;
5166 
5167   // If the backedge is guarded by a comparison with the pre-inc  value the
5168   // addrec is safe. Also, if the entry is guarded by a comparison with the
5169   // start value and the backedge is guarded by a comparison with the post-inc
5170   // value, the addrec is safe.
5171   if (isKnownPositive(Step)) {
5172     const SCEV *N = getConstant(APInt::getMinValue(BitWidth) -
5173                                 getUnsignedRangeMax(Step));
5174     if (isLoopBackedgeGuardedByCond(L, ICmpInst::ICMP_ULT, AR, N) ||
5175         isKnownOnEveryIteration(ICmpInst::ICMP_ULT, AR, N)) {
5176       Result = setFlags(Result, SCEV::FlagNUW);
5177     }
5178   }
5179 
5180   return Result;
5181 }
