5185 /// Represents an abstract binary operation.  This may exist as a
5186 /// normal instruction or constant expression, or may have been
5187 /// derived from an expression tree.
5188 struct BinaryOp {
5189   unsigned Opcode;
5190   Value *LHS;
5191   Value *RHS;
5192   bool IsNSW = false;
5193   bool IsNUW = false;
5194 
5195   /// Op is set if this BinaryOp corresponds to a concrete LLVM instruction or
5196   /// constant expression.
5197   Operator *Op = nullptr;
5198 
5199   explicit BinaryOp(Operator *Op)
5200       : Opcode(Op->getOpcode()), LHS(Op->getOperand(0)), RHS(Op->getOperand(1)),
5201         Op(Op) {
5202     if (auto *OBO = dyn_cast<OverflowingBinaryOperator>(Op)) {
5203       IsNSW = OBO->hasNoSignedWrap();
5204       IsNUW = OBO->hasNoUnsignedWrap();
5205     }
5206   }
5207 
5208   explicit BinaryOp(unsigned Opcode, Value *LHS, Value *RHS, bool IsNSW = false,
5209                     bool IsNUW = false)
5210       : Opcode(Opcode), LHS(LHS), RHS(RHS), IsNSW(IsNSW), IsNUW(IsNUW) {}
5211 };
5212 
5213 } // end anonymous namespace
