5215 /// Try to map \p V into a BinaryOp, and return \c std::nullopt on failure.
5216 static std::optional<BinaryOp> MatchBinaryOp(Value *V, const DataLayout &DL,
5217                                              AssumptionCache &AC,
5218                                              const DominatorTree &DT,
5219                                              const Instruction *CxtI) {
5220   auto *Op = dyn_cast<Operator>(V);
5221   if (!Op)
5222     return std::nullopt;
5223 
5224   // Implementation detail: all the cleverness here should happen without
5225   // creating new SCEV expressions -- our caller knowns tricks to avoid creating
5226   // SCEV expressions when possible, and we should not break that.
5227 
5228   switch (Op->getOpcode()) {
5229   case Instruction::Add:
5230   case Instruction::Sub:
5231   case Instruction::Mul:
5232   case Instruction::UDiv:
5233   case Instruction::URem:
5234   case Instruction::And:
5235   case Instruction::AShr:
5236   case Instruction::Shl:
5237     return BinaryOp(Op);
5238 
5239   case Instruction::Or: {
5240     // LLVM loves to convert `add` of operands with no common bits
5241     // into an `or`. But SCEV really doesn't deal with `or` that well,
5242     // so try extra hard to recognize this `or` as an `add`.
5243     if (haveNoCommonBitsSet(Op->getOperand(0), Op->getOperand(1), DL, &AC, CxtI,
5244                             &DT, /*UseInstrInfo=*/true))
5245       return BinaryOp(Instruction::Add, Op->getOperand(0), Op->getOperand(1),
5246                       /*IsNSW=*/true, /*IsNUW=*/true);
5247     return BinaryOp(Op);
5248   }
5249 
5250   case Instruction::Xor:
5251     if (auto *RHSC = dyn_cast<ConstantInt>(Op->getOperand(1)))
5252       // If the RHS of the xor is a signmask, then this is just an add.
5253       // Instcombine turns add of signmask into xor as a strength reduction step.
5254       if (RHSC->getValue().isSignMask())
5255         return BinaryOp(Instruction::Add, Op->getOperand(0), Op->getOperand(1));
5256     // Binary `xor` is a bit-wise `add`.
5257     if (V->getType()->isIntegerTy(1))
5258       return BinaryOp(Instruction::Add, Op->getOperand(0), Op->getOperand(1));
5259     return BinaryOp(Op);
5260 
5261   case Instruction::LShr:
5262     // Turn logical shift right of a constant into a unsigned divide.
5263     if (ConstantInt *SA = dyn_cast<ConstantInt>(Op->getOperand(1))) {
5264       uint32_t BitWidth = cast<IntegerType>(Op->getType())->getBitWidth();
5265 
5266       // If the shift count is not less than the bitwidth, the result of
5267       // the shift is undefined. Don't try to analyze it, because the
5268       // resolution chosen here may differ from the resolution chosen in
5269       // other parts of the compiler.
5270       if (SA->getValue().ult(BitWidth)) {
5271         Constant *X =
5272             ConstantInt::get(SA->getContext(),
5273                              APInt::getOneBitSet(BitWidth, SA->getZExtValue()));
5274         return BinaryOp(Instruction::UDiv, Op->getOperand(0), X);
5275       }
5276     }
5277     return BinaryOp(Op);
5278 
5279   case Instruction::ExtractValue: {
5280     auto *EVI = cast<ExtractValueInst>(Op);
5281     if (EVI->getNumIndices() != 1 || EVI->getIndices()[0] != 0)
5282       break;
5283 
5284     auto *WO = dyn_cast<WithOverflowInst>(EVI->getAggregateOperand());
5285     if (!WO)
5286       break;
5287 
5288     Instruction::BinaryOps BinOp = WO->getBinaryOp();
5289     bool Signed = WO->isSigned();
